/* Aula 19 — modelJs: classList, atributos, dataset */

const btn = document.querySelector('#toggle');
const card = document.querySelector('#card');
const msg = document.querySelector('.msg');

if (btn && card && msg) {
  // 1) Toggle visual
  card.classList.toggle('ativo');

  // 2) Dataset: ler e trocar
  const atual = btn.dataset.mode; // 'off' ou 'on'
  const novo = atual === 'off' ? 'on' : 'off';
  btn.dataset.mode = novo;

  // 3) Atualizar texto
  msg.textContent = `Estado: ${novo.toUpperCase()}`;

  // 4) Ler atributo data-id do card
  console.log('card data-id:', card.getAttribute('data-id'));
}
